   234→/**
   235→ * Progress update during optimization
   236→ */
   237→export interface OptimizerProgressMessage {
   238→  type: 'PROGRESS';
   239→  requestId: string;
   240→  percent: number;
   241→  currentObjective: number;
   242→  feasible: boolean;
   243→  elapsedMs: number;
   244→}
   245→
   246→/**
   247→ * Heartbeat message during optimization
   248→ */
   249→export interface OptimizerHeartbeatMessage {
   250→  type: 'HEARTBEAT';
   251→  requestId: string;
   252→  timestamp: number;
   253→  memoryMb: number;
   254→  threadCount: number;
   255→  branchesPerSecond: number;
   256→}
   257→
   258→/**
   259→ * Error message from optimizer
   260→ */
   261→export interface OptimizerErrorMessage {
   262→  type: 'ERROR';
   263→  requestId: string;
   264→  errorCode: 'SEGFAULT' | 'TIMEOUT' | 'OOM' | 'INVALID_INPUT' | 'INTERNAL_ERROR';
   265→  errorMessage: string;
   266→  stackTrace?: string;
   267→  lastProgress?: {
   268→    percent: number;
   269→    branchesExplored: number;
   270→    memoryMb: number;
   271→  };
   272→  recoverySuggestion: string;
   273→}
   274→
   275→/**
   276→ * Union of all optimizer output messages
