   455→  };
   456→
   457→  // Add job to queue
   458→  const { id: jobId } = await addJob(
   459→    QUEUE_NAMES.TACTICAL_SCHEDULER,
   460→    'tactical-schedule',
   461→    jobData
   462→  );
   463→
   464→  return c.json(
   465→    success(
   466→      {
   467→        jobId,
   468→        status: 'QUEUED',
   469→        horizonWeeks,
   470→        dryRun: body.dryRun ?? false,
   471→      },
   472→      {
   473→        timing: { durationMs: getRequestDuration(c) },
   474→      }
   475→    ),
   476→    202
   477→  );
   478→});
   479→
   480→/**
   481→ * POST /optimizer/strategic-plan
   482→ *
   483→ * Trigger strategic planning for a 10-year horizon.
   484→ * Uses genetic algorithm to optimize long-term PM scheduling
   485→ * and resource allocation.
   486→ */
   487→optimizerRoutes.post('/optimizer/strategic-plan', async (c) => {
   488→  const requestId = getRequestId(c);
   489→
   490→  // Parse request body
   491→  let body: StrategicPlanRequest;
   492→  try {
   493→    body = await c.req.json();
   494→  } catch {
   495→    body = {}; // Allow empty body for default parameters
   496→  }
   497→
   498→  // Validate fromBaselineId if provided
   499→  if (body.fromBaselineId && !isValidUuid(body.fromBaselineId)) {
   500→    return c.json(
   501→      error(
   502→        ErrorCodes.VALIDATION_ERROR,
   503→        'Invalid fromBaselineId format. Expected UUID',
   504→        requestId,
   505→        { field: 'fromBaselineId', value: body.fromBaselineId }
   506→      ),
   507→      400
   508→    );
   509→  }
   510→
   511→  // Validate fleetId if provided
   512→  if (body.fleetId && !isValidUuid(body.fleetId)) {
   513→    return c.json(
   514→      error(
   515→        ErrorCodes.VALIDATION_ERROR,
   516→        'Invalid fleetId format. Expected UUID',
   517→        requestId,
   518→        { field: 'fleetId', value: body.fleetId }
   519→      ),
   520→      400
   521→    );
   522→  }
   523→
   524→  // Validate horizonYears
   525→  const horizonYears = body.horizonYears ?? 10;
   526→  if (horizonYears < 1 || horizonYears > 15) {
   527→    return c.json(
   528→      error(
   529→        ErrorCodes.VALIDATION_ERROR,
   530→        'horizonYears must be between 1 and 15',
