   572→
   573→  // Add job to queue
   574→  const { id: jobId } = await addJob(
   575→    QUEUE_NAMES.STRATEGIC_PLANNER,
   576→    'strategic-plan',
   577→    jobData
   578→  );
   579→
   580→  // Estimate completion time for strategic planning (much longer)
   581→  const estimatedCompletionSeconds = Math.ceil(
   582→    (populationSize * generations) / 100 + 60
   583→  );
   584→
   585→  return c.json(
   586→    success(
   587→      {
   588→        jobId,
