/**
 * MMS Run Assignment Solver
 *
 * CP-SAT solver for train-to-route assignment optimization.
 * Uses Google OR-Tools for constraint programming.
 *
 * @see specs/004-domain-services.md Section 4.3.3
 */

#pragma once

#include <nlohmann/json.hpp>
#include <string>
#include <vector>
#include <unordered_map>
#include <functional>
#include <optional>

namespace mms {

using json = nlohmann::json;

/**
 * Explanation factor for assignment decisions
 */
struct ExplanationFactor {
    std::string constraintType;  // "HARD" or "SOFT"
    std::string constraintName;
    double impact;
    std::string description;

    json toJson() const;
};

/**
